def count_distinct_pairs(nums, target):
    if not nums:
        return 0

    num_set = set(nums)
    pairs = set()

    for num in num_set:
        complement = target - num
        if complement in num_set and (complement, num) not in pairs:
            pairs.add((num, complement))

    return len(pairs)
